def lcs(s1, s2): 
    # Initialize LCS array with length 0 for both strings 
    l = [[[0] * len(s) for _ in range(len(s))]for _ in range(len(s1), 0,-1)]

    # Find LCS from s1 to end of s2 and store it in l[i][j]  
    for i in range(len(s1)): 
        for j in range(len(s2)+1, len(l)) : 
            if (i+1 < len(s1) and l[i][j-1] == l[i][j] + 1 or 
                i+1 >= len(s1) or j > len(s2) or l[i][j-1] != l[i+1][j-1]): 
                    break; 
            else: 
                l[i][j] = max(l[i][j-1], l[i+1][j]) 

    return l[len(s1)-1][len(s2)]

def fibonacci(n): 
    # Base case 
    if (n == 0) or (n == 1):  
        return 0

    elif (n < 0): 
        print("Incorrect input") 

    # Recursive case 
    else: 
        result = fibonacci(n-1)+fibonacci(n-2) 

        return result 

