def binary_search(arr, target): 
    left = 0
    right = len(arr)-1

    while left <= right: 
        mid = (left+right) // 2

        if arr[mid] == target: 
            return mid

        elif target < arr[mid]: 
            right = mid - 1

        else: 
            left = mid + 1

    return -1

class Queue(object): 
    """A simple implementation of a queue data structure using two stacks"""

    def __init__(self, maxsize=10):  
        self._front = None # front of the queue
        self._back = None # back of the queue

        if maxsize > 0:
            self._create_stack()

        else:
            self._replenish_queue()

    def _create_stack(self):
        """Creates and initializes two stacks for this queue."""
        self.__front = []
        self.__back = [None] * (maxsize + 1)

    def _replenish_queue(self):
        """Replenishes the queue when it becomes empty."""
