    def __remove(self, value):
        index = self.__find(value)

        if index != -1:
            del self.__back[index]

        elif len(self.__back) == 0:
            raise Exception("Queue Empty")

    def __find(self, value):
        for i in range(len(self.__back)):
            if self.__back[i] == value:
