def findCommonElements(arr1, arr2): 
    # initialize result array  
    res = [] 

    # loop through both arrays and check for matching elements 
    for i in range(len(arr1)): 
        if (i == len(arr1) - 1 or arr1[i] != arr2[i + 1]): 
            continue 

        while (True): 
            j = i+1
            while (j < len(arr2)) : 
                if (arr1[i] == arr2[j]) break 
                else j += 1                        
            if (j >= len(arr2)) break 

            res.append(arr1[i]) 

